head.script:
/*
 * 화 면 명 : 협력업체차량작업지시(벌크)
 * 메뉴경로 : 물류(D)/국내운영/협력업체차량작업지시(벌크)
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/ds/op/wrkplan/transwrkplan/op_202_02_24b.jsp
 * 작 성 자 : 유청아
 * 작 업 일 : 2026-03-23
  * 수정이력 :
 *    - 2026-03-23      유청아    최초작성
 *    - 2026-04-23      이진우    T-7308 결함처리
 */
// op_101_01_18p, op_101_01_19p 삭제되어서 운송차량 그리드의 단축번호 검색은 없애고 관련 셀은 edit로 수정

scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd"); //현재일자
scwin.gv_userClsCd = $c.data.getMemInfo("userClsCd");	// 사용자 구분코드
scwin.gv_clntNo = $c.data.getMemInfo("clntNo");
scwin.gv_clntNm = $c.data.getMemInfo("clntNm");
scwin.gv_loabranCd = $c.data.getMemInfo("loUpperLobranCd");

scwin.btnFlag = ""; // 신규, 수정 구분자
//scwin.rowFlag = ""; // 등록, 수정 후 저장 안하고 다른 master row 선택 불가능 구분자 //SET하는곳 없음

scwin.pos_groupCode = 0; // 저장전 DataSet의 RowPosition을 저장 변수

//-------------------------------------------------------------------------
// 페이지로드
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "OP190", compID: "acb_con_workGubun" }, //작업구분
        { grpCd: "SD113", compID: "acb_con_odrKndCd" } //오더종류
    ];
    $c.data.setCommonCode(codeOptions);

    //EBC 코드 조회
    const codeOptions2 = [
        { //배차점소
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retriveLobran2CodeList",
            compID: "acb_lobranCd"
        },
        { //작업권역1
            method: "getLuxeComboData",
            param1: "DsCommonEBC",
            param2: "retriveWrkDistrictCdCombo",
            compID: "acb_districtCd"
        },
        { //작업권역2
            method: "getLuxeComboData",
            param1: "DsCommonEBC",
            param2: "retriveWrkDistrictCdCombo",
            compID: "acb_districtCd2"
        }
    ];

    $c.data.setGauceUtil(codeOptions2, function () {
        if (scwin.gv_loabranCd) {
            acb_lobranCd.setValue(scwin.gv_loabranCd);
        }
    });

    //협력업체 차량종류
    scwin.f_vehclKnd();

    //협력업체 차량규격
    scwin.f_vehclNrm();

    //입력 그리드 maxlength 설정
    scwin.f_SetGridColumnMaxLength(gr_results1);
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $p.setTimeout(function () {
        //소스
        scwin.f_switchObjMode(1); //화면로딩

        ed_dptIntendDd.setValue(scwin.vCurDate);
        ed_dptIntendDdTo.setValue(scwin.vCurDate);

        //테스트 데이터
        // ed_clntNo.setValue("102943");
        // ed_dptIntendDd.setValue("20090110");
        // ed_dptIntendDdTo.setValue("20090110");
    }, { "delay": 100 });
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트 호출
//-------------------------------------------------------------------------
scwin.ondataload = function () {
    //작업구분
    acb_con_workGubun.setValue(DsConstants.CARGO_CLS_CD_BULK);
};

//-------------------------------------------------------------------------
// 입력 그리드 maxlength 설정
//-------------------------------------------------------------------------
scwin.f_SetGridColumnMaxLength = function (gridViewObj) {
    for (let i = 0; i < gridViewObj.getTotalCol(); i++) {
        let colNm = gridViewObj.getColumnID(i);
        let dataObj = $c.gus.object(gridViewObj.getDataList());
        let colInfo = dataObj.getColumnInfo(colNm);

        if (typeof colInfo != "undefined") {
            gridViewObj.setMaxLength(i, colInfo.length);
        }
    }
};

//-------------------------------------------------------------------------
// 화면구성요소 제어(버튼 입력박스등등 disable, enable)
//-------------------------------------------------------------------------
scwin.f_switchObjMode = function (gubun) {
    switch (gubun) {
        case 1: //화면로딩
            scwin.btnFlag = "";
            $c.gus.cfDisableKeyData();

            if (scwin.gv_userClsCd != "01") {
                ed_clntNo.setValue(scwin.gv_clntNo);
                ed_clntNm.setValue(scwin.gv_clntNm);
                $c.gus.cfDisableObjects([ed_clntNo, ed_clntNm, btn_clntNo]);
            } else {
                ed_clntNo.focus();
            }

            $c.gus.cfDisableBtn([$c.gus.getctrlBtn('bSave'), $c.gus.getctrlBtn('bDelete')]);
            $c.gus.cfDisableObjects([btn_addRow, btn_deleteRow, btn_cancelRow]);
            $c.gus.cfDisableObjects([btn_vehcl]);
            break;
        case 2: //조회
            break;
        case 3: //신규
            break;
        case 4: //수정
            break;
        case 5: //조회완료
            scwin.btnFlag = "";
            scwin.f_switchObjMode(1); //화면로딩

            if (ds_results.getRowCount() == 0)
                return;

            $c.gus.cfEnableBtnOnly([$c.gus.getctrlBtn('bSave'), $c.gus.getctrlBtn('bDelete')]);
            $c.gus.cfEnableObjects([btn_vehcl]);
            $c.gus.cfEnableObjects([btn_addRow, btn_deleteRow, btn_cancelRow]);
            break;
        case 6: //수정불가
            break;
        case 7: //행삭제, 행취소
            break;
        case 8: //행추가
            break;
        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (gubun) {
    if (!await $c.gus.cfValidate([ed_clntNo])) {
        return;
    }

    if (gubun == null || gubun == "" || gubun == 0) {
        ds_results1.setJSON([]);
        ds_results2.setJSON([]);

        ds_search.setEmptyValue(); //tobe추가

        ds_search.set("workGubun", acb_con_workGubun.getValue());
        ds_search.set("lobranCd", acb_lobranCd.getValue());
        ds_search.set("odrKndCd", acb_con_odrKndCd.getValue());
        ds_search.set("odrNo", ed_orderNo.getValue().trim());
        ds_search.set("vsslCd", ed_vsslCd.getValue().trim());
        ds_search.set("portcnt", ed_portcnt.getValue().trim());
        ds_search.set("dptDistrictCd", acb_districtCd.getValue());
        ds_search.set("arvDistrictCd", acb_districtCd2.getValue());
        ds_search.set("dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
        ds_search.set("arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());
        ds_search.set("dptIntendDd", ed_dptIntendDd.getValue().trim());
        ds_search.set("dptIntendDdTo", ed_dptIntendDdTo.getValue().trim());
        ds_search.set("schGubun", acb_schGubun.getValue().trim());
        ds_search.set("clntNo", ed_clntNo.getValue().trim());
        ds_search.set("commCd", ed_commCd.getValue().trim());
        ds_search.set("wrkIndictNo", ed_workIndictNo.getValue().trim());
        ds_search.set("blNo", ed_blNo.getValue().trim());

        var sameMmchaDt = eval(ed_dptIntendDdTo.getValue()) - eval(ed_dptIntendDd.getValue());
        var defMmchaDt = 0;
        var subFrom = ed_dptIntendDd.getValue().substring(4, 2);

        if (subFrom == "01" || subFrom == "03" || subFrom == "05" || subFrom == "07" || subFrom == "08" || subFrom == "10") {
            defMmchaDt = eval(ed_dptIntendDdTo.getValue()) - (eval(ed_dptIntendDd.getValue()) + 68);
        } else if (subFrom == "02") {
            defMmchaDt = eval(ed_dptIntendDdTo.getValue()) - (eval(ed_dptIntendDd.getValue()) + 71);
        } else if (subFrom == "04" || subFrom == "06" || subFrom == "09" || subFrom == "11") {
            defMmchaDt = eval(ed_dptIntendDdTo.getValue()) - (eval(ed_dptIntendDd.getValue()) + 69);
        } else if (subFrom == "12") {
            defMmchaDt = eval(ed_dptIntendDdTo.getValue()) - (eval(ed_dptIntendDd.getValue()) + 8868);
        }

        if ((ed_dptIntendDd.getValue().substring(4, 2) == ed_dptIntendDdTo.getValue().substring(4, 2) && sameMmchaDt > 10) || (ed_dptIntendDd.getValue().substring(4, 2) != ed_dptIntendDdTo.getValue().substring(4, 2) && defMmchaDt > 10)) { //시작날짜와 종료날짜의 달이 틀릴경우
            $c.win.alert("화주오더(오더전송)일자 조회기간을 최대 10일까지만 조회해주세요.");
            ed_dptIntendDd.focus();
            return;
        }

        ds_results.setJSON([]);
        $c.sbm.execute(sbm_retrieve);
    } else if (gubun == 1) {
        // 조회조건복사
        if (ds_results.getRowCount() == 0)
            return;

        var v_features = "copyHeader=yes,rowFrom=" + ds_results.getRowPosition() + ",rowCnt=1";
        $c.gus.cfCopyDataSet(ds_results, ds_search1, v_features);

        ds_results1.setJSON([]);
        ds_results2.setJSON([]);
        $c.sbm.execute(sbm_retrieve1);
    }
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (scwin.f_isCompleteOrder(ds_results, ds_results.getRowPosition())) {
        $c.gus.cfAlertMsg("완료된 오더정보는 수정할 수 없습니다");
        return;
    }

    let ret = await $c.gus.cfValidate([gr_results1]);
    if (!ret) {
        return;
    }

    //변경한 데이터가 있는지 체크한다.    
    if (ds_results.getModifiedIndex().length == 0 && ds_results1.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    //협력업체등록정보와 차량등록정보가 일치하는지를 체크한다
    var v_totalCnt = 0;
    for (var i = 0; i < ds_results2.getRowCount(); i++) {
        var v_clntNo = ds_results2.getCellData(i, 'clntNo');
        var v_clntNm = ds_results2.getCellData(i, 'clntNm');
        var v_eqKndCd = ds_results2.getCellData(i, 'eqKndCd');
        var v_eqKndNm = ds_results2.getCellData(i, 'eqKndNm');
        var v_eqNrmCd = ds_results2.getCellData(i, 'eqNrmCd');
        var v_eqNrmNm = ds_results2.getCellData(i, 'eqNrmNm');
        var v_reqVehclCnt = ds_results2.getCellData(i, 'reqVehclCnt');
        var v_vehclCnt = 0;

        v_totalCnt += v_reqVehclCnt;
        for (var j = 0; j < ds_results1.getRowCount(); j++) {
            if (v_clntNo == ds_results1.getCellData(j, 'clntNo')
                && v_eqKndCd == ds_results1.getCellData(j, 'eqKndCd')
                && v_eqNrmCd == ds_results1.getCellData(j, 'eqNrmCd')) {
                v_vehclCnt++;
            }
        }

        if (v_vehclCnt != v_reqVehclCnt) {
            $c.gus.cfAlertMsg("협력업체 : [" + v_clntNo + "]" + v_clntNm + "<br>"
                + "차량종류 : [" + v_eqKndCd + "]" + v_eqKndNm + "<br>"
                + "차량규격 : [" + v_eqNrmCd + "]" + v_eqNrmNm + "<br>"
                + "차량대수 : " + v_reqVehclCnt + "<br>"
                + "협력업체정보와 운송차량정보가 다릅니다"
            );
            return;
        }
    }

    if (v_totalCnt != ds_results1.getRowCount()) {
        $c.gus.cfAlertMsg("협력업체정보에 등록된 차량대수와 운송차량정보의 차량대수가 다릅니다");
        return;
    }

    if (ds_results1.getModifiedIndex().length != 0) {
        if (ds_results.getCellData(ds_results.getRowPosition(), "indvdlAlloccarYn") == 0) {
            var v_transWrkIndictNo = ds_results.getCellData(ds_results.getRowPosition(), "transWrkIndictNo");

            for (var i = 0; i < ds_results.getRowCount(); i++) {
                if (ds_results.getCellData(i, "transWrkIndictNo") == v_transWrkIndictNo) {
                    //ds_results.UserStatus(i) = 1;
                    ds_results.modifyRowStatus(i, "C");
                }
            }
        } else {
            //ds_results.UserStatus(ds_results.setRowPosition) = 1;
            ds_results.modifyRowStatus(ds_results.getRowPosition(), "C");
        }
        //sbm_save.KeyValue = "JSP(I:IN_DS1=ds_results,I:IN_DS2=ds_results1,I:IN_DS3=ds_results2)"; 
    } else {
        //TOBE에서는 IN_DS 3개를 모두 보내야함(modified 되는것만 보내니 상관없을듯)
        //sbm_save.KeyValue = "JSP(I:IN_DS1=ds_results,I:IN_DS3=ds_results2)";
    }

    if (ds_results.getCellData(ds_results.getRowPosition(), 'carryingOutAdmissionYn') == 0) {
        ret = await $c.win.confirm("반출승인이 나지 않은 오더입니다. 계속하시겠습니까?");
        if (!ret) {
            return;
        }
    }

    ret = await $c.win.confirm("저장하시겠습니까?");
    if (ret) {
        scwin.pos_groupCode = ds_results.getRowPosition(); // 저장 전의 위치 저장
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    if (scwin.f_isCompleteOrder(ds_results, ds_results.getRowPosition())) {
        $c.gus.cfAlertMsg("완료된 오더정보는 삭제할 수 없습니다");
        return;
    }

    if (ds_results.getCellData(ds_results.getRowPosition(), "indvdlAlloccarYn") == 0) {
        var v_transWrkIndictNo = ds_results.getCellData(ds_results.getRowPosition(), "transWrkIndictNo");
        for (var i = 0; i < ds_results.getRowCount(); i++) {
            if (ds_results.getCellData(i, "transWrkIndictNo") == v_transWrkIndictNo) {
                //ds_results.UserStatus(i) = 2;
                ds_results.modifyRowStatus(i, "D");
            }
        }
    } else {
        //ds_results.UserStatus(ds_results.setRowPosition) = 2;
        ds_results.modifyRowStatus(ds_results.getRowPosition(), "D");
    }

    for (var i = ds_results1.getRowCount() - 1; i >= 0; i--) {
        if (ds_results1.getRowStatus(i) == "C") {
            ds_results1.removeRow(i)
        } else {
            ds_results1.deleteRow(i);
        }
    }

    for (var i = ds_results2.getRowCount() - 1; i >= 0; i--) {
        if (ds_results2.getRowStatus(i) == "C") {
            ds_results2.removeRow(i)
        } else {
            ds_results2.deleteRow(i);
        }
    }

    // ds_results1.DeleteAll();
    // ds_results2.DeleteAll();

    let ret = await $c.win.confirm("삭제하시겠습니까?");
    if (ret) {
        $c.sbm.execute(sbm_save);
    }

/////////////
    if (ds_results.getCellData(ds_results.getRowPosition(), "indvdlAlloccarYn") == 0) {
        var v_transWrkIndictNo = ds_results.getCellData(ds_results.getRowPosition(), "transWrkIndictNo");
        for (var i = 0; i < ds_results.getRowCount(); i++) {
            if (ds_results.getCellData(i, "transWrkIndictNo") == v_transWrkIndictNo) {
                ds_results.modifyRowStatus(i, "R");
            }
        }
    } else {
        ds_results.modifyRowStatus(ds_results.getRowPosition(), "R");
    }

    for (var i = ds_results1.getRowCount() - 1; i >= 0; i--) {
        if (ds_results1.getRowStatus(i) == "C") {
            ds_results1.modifyRowStatus(i, "R");
        } else {
            ds_results1.modifyRowStatus(i, "R");
        }
    }

    for (var i = ds_results2.getRowCount() - 1; i >= 0; i--) {
        if (ds_results2.getRowStatus(i) == "C") {
            ds_results2.modifyRowStatus(i, "R");
        } else {
            ds_results2.modifyRowStatus(i, "R");
        }
    }

}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1:
            //선박명
            udc_vsslCd.setSelectId("retrieveVsslCdInfo"); // XML상의 SELECT ID             
            udc_vsslCd.cfCommonPopUp(scwin.udc_vsslCd_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , null // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
        case 2:
            //출발지            
            udc_dptWrkPlCd.setSelectId("retrieveWrkPlInfo"); // XML상의 SELECT ID
            udc_dptWrkPlCd.cfCommonPopUp(scwin.udc_dptWrkPlCd_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , ",,,3" // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , null // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
        case 3:
            //도착지            
            udc_arvWrkPlCd.setSelectId("retrieveWrkPlInfo"); // XML상의 SELECT ID
            udc_arvWrkPlCd.cfCommonPopUp(scwin.udc_arvWrkPlCd_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , ",,,3" // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , null // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
        case 4:
            // 협력업체(차량매입)
            udc_clntNo.setSelectId("retrieveCarKindClntInfo"); // XML상의 SELECT ID
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , DsConstants.PCHS_CLNT_CLS_CD_HIRECAR // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "협력업체,협력업체코드,협력업체명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
        case 5:
            //품명            
            udc_commCd.setSelectId("retrieveCommInfo"); // XML상의 SELECT ID
            udc_commCd.cfCommonPopUp(scwin.udc_commCd_callBackFunc // XML상의 SELECT ID
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , null // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 차량조회
//-------------------------------------------------------------------------
scwin.f_vehclSearch = async function (bAddRowFlag, bCloseFlag, bSpotFlag) {
    var v_AddRowFlag = (bAddRowFlag == true) ? 'T' : 'F';
    var v_CloseFlag = (bCloseFlag == true) ? 'T' : 'F';

    if (scwin.f_isCompleteOrder(ds_results, ds_results.getRowPosition())) {
        $c.gus.cfAlertMsg("완료된 오더정보는 수정할 수 없습니다");
        return;
    }

    if (ds_results.getRowCount() == 0) {
        $c.gus.cfAlertMsg("선택한 운송물량정보가 없습니다");
    }

    //합적인경우 차량은 한대만 등록가능
    if (bAddRowFlag
        && ds_results.getCellData(ds_results.getRowPosition(), "coshippingNo") != ""
        && ds_results1.getRowCount() > 0) {
        $c.gus.cfAlertMsg("합적물량은 차량을 한대만 등록할 수 있습니다");
        return;
    }

    var arrParam = new Array();
    var rtnList = new Array();

    var v_vehclShortCd = "";
    var v_vehclSchCond = "";
    //계약거래처가 동부한농화학이고 품목이 복합비료인경우에는 차량규격중 5, 25Ton만 가능하다
    if (ds_results.getRowCount() > 0
        && ds_results.getCellData(ds_results.getRowPosition(), 'ctrtClntNo') == DsConstants.CTRT_CLNT_NO_HANNONG
        && ds_results.getCellData(ds_results.getRowPosition(), 'upperCommCd') == DsConstants.COMM_CD_COMPOSITE_FERTILIZER) {
        v_vehclSchCond = "1";
    }

    if (ds_results1.getRowCount() > 0 && bCloseFlag) {
        v_vehclShortCd = ds_results1.getCellData(ds_results1.getRowPosition(), "vehclShortCd");
    }

    if (bSpotFlag) {
        var v_bondTransExpireDt = ds_results.getCellData(ds_results.getRowPosition(), "bondTransExpireDt");
        arrParam[0] = new Array(ds_results2.getCellData(ds_results2.getRowPosition(), "clntNo")
            , ds_results2.getCellData(ds_results2.getRowPosition(), "clntNm")
            , v_vehclShortCd
            , v_vehclSchCond); //검색조건
        arrParam[1] = new Array(v_bondTransExpireDt, v_CloseFlag); //보세운송만료일자

        var win_url = "/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_18p.xml";

        let opts = {
            id: "op_101_01_18p",
            popupName: "SPOT 차량 조회",
            modal: true,
            type: "browserPopup",
            width: 1000,
            height: 700,
            title: "SPOT 차량 조회"
        };

        rtnList = await $c.win.openPopup(win_url, opts, arrParam);
    } else {
        var v_bondTransExpireDt = ds_results.getCellData(ds_results.getRowPosition(), "bondTransExpireDt");

        arrParam[0] = new Array(acb_lobranCd.getValue() //0 점소
            , DsConstants.WRK_DST_CLS_CD_J //1 작업구간
            , acb_districtCd.getValue() //2 권역
            , acb_con_workGubun.getValue() //3 화물구분
            , ds_results.getCellData(ds_results.getRowPosition(), "wrkStDt") //4 작업시작일
            , v_vehclShortCd //5 차량단축번호
            , ds_results2.getCellData(ds_results2.getRowPosition(), "clntNo") //6 협력업체코드
            , ds_results2.getCellData(ds_results2.getRowPosition(), "clntNm") //7 협력업체명
            , v_vehclSchCond //8 조회조건(동부한농 복합비료등 예외조건)
            , DsConstants.EQ_KND_CD_TR //9 차량종류
        ); //검색조건

        arrParam[1] = new Array(v_bondTransExpireDt //보세운송만료일자
            , v_CloseFlag //AutoClose 여부
            , v_AddRowFlag //전체검색여부
        );

console.log("arrParam[0]::",arrParam[0]);
console.log("arrParam[1]::",arrParam[1]);

        var win_url = "/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_19p.xml";

        let opts = {
            id: "op_101_01_19p",
            popupName: "협력업체관리차량조회",
            modal: true,
            type: "browserPopup",
            width: 1250,
            height: 600,
            title: "협력업체관리차량조회"
        };

        rtnList = await $c.win.openPopup(win_url, opts, arrParam);
    }

    console.log("rtnList[0]::", rtnList[0]);
    console.log("rtnList[0][0]::", rtnList[0][0]);
    console.log("rtnList::", rtnList);

    // if (rtnList == null || (rtnList[0][0] == null && rtnList[0] == "N/A")) {
    if (rtnList == null || rtnList[0] == "N/A") {
        //단축번호로 직접 조회한경우 해당로우를 삭제한다
        if (!bAddRowFlag) {
            $c.data.undoRow(ds_results1, false);
        }

        return;
    }

    var firstList = new Array();

    for (var i = 0; i < rtnList.length; i++) {
        if (ds_results.getCellData(ds_results.getRowPosition(), "coshippingNo") != "" && i > 0) {
            break;
        }
        firstList = rtnList[i];

        if ((bAddRowFlag && i == 0) || i > 0) {
            var newRow = ds_results1.insertRow();
            ds_results1.setRowPosition(newRow);
        }

        var row = ds_results1.getRowPosition();
        if (bSpotFlag) {
            ds_results1.setCellData(row, "spotYn", 1);
        }
        ds_results1.setCellData(row, "vehclNo", firstList[0]);
        ds_results1.setCellData(row, "eqCd", firstList[1]);
        ds_results1.setCellData(row, "eqKndCd", ds_results2.getCellData(0, "eqKndCd"));
        ds_results1.setCellData(row, "eqKndNm", ds_results2.getCellData(0, "eqKndNm"));
        ds_results1.setCellData(row, "eqNrmCd", ds_results2.getCellData(0, "eqNrmCd"));
        ds_results1.setCellData(row, "eqNrmNm", ds_results2.getCellData(0, "eqNrmNm"));
        ds_results1.setCellData(row, "clntNo", firstList[6]);
        ds_results1.setCellData(row, "clntNm", firstList[7]);
        ds_results1.setCellData(row, "vehclShortCd", firstList[8]);
        ds_results1.setCellData(row, "drvEmpNo", firstList[9]);
        ds_results1.setCellData(row, "drvNm", firstList[10]);
        ds_results1.setCellData(row, "mpNo", firstList[11]);
        ds_results1.setCellData(row, "trsNo", firstList[12]);
        ds_results1.setCellData(row, "chassisEqCd", firstList[13]);
        ds_results1.setCellData(row, "chassisNo", firstList[14]);
        ds_results1.setCellData(row, "chassisKndCd", firstList[15]);
        ds_results1.setCellData(row, "chassisKndNm", firstList[16]);
        ds_results1.setCellData(row, "assgnLobranCd", firstList[19]);
        ds_results1.setCellData(row, "posnClsCd", firstList[20]);
        ds_results1.setCellData(row, "wrkIndictYn", firstList[21]);

        ds_results1.setCellData(row, "transWrkIndictNo", ds_results.getCellData(ds_results.getRowPosition(), "transWrkIndictNo"));
        ds_results1.setCellData(row, "odrNo", ds_results.getCellData(ds_results.getRowPosition(), "odrNo"));
        ds_results1.setCellData(row, "commSeq", ds_results.getCellData(ds_results.getRowPosition(), "commSeq"));
        ds_results1.setCellData(row, "wrkPathSeq", ds_results.getCellData(ds_results.getRowPosition(), "wrkPathSeq"));
        ds_results1.setCellData(row, "wrkStpSeq", ds_results.getCellData(ds_results.getRowPosition(), "wrkStpSeq"));
    }

    return false;
}

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function (gubun) {
    if (scwin.f_isCompleteOrder(ds_results, ds_results.getRowPosition())) {
        $c.gus.cfAlertMsg("완료된 오더정보는 수정할 수 없습니다");
        return;
    }

    if (gubun == null || gubun == "" || gubun == 0) {
        //합적인경우 차량은 한대만 등록가능
        if (ds_results.getCellData(ds_results.getRowPosition(), "coshippingNo") != ""
            && ds_results1.getRowCount() > 0) {
            $c.gus.cfAlertMsg("합적물량은 차량을 한대만 등록할 수 있습니다");
            return;
        }

        var newRow = ds_results1.insertRow();
        ds_results1.setRowPosition(newRow);
    }

    scwin.f_switchObjMode(8); //행추가
}

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = function (gubun) {
    if (gubun == null || gubun == "" || gubun == 0) {
        if (ds_results1.getRowStatus(ds_results1.getRowPosition()) == "C") {
            ds_results1.removeRow(ds_results1.getRowPosition())
        } else {
            ds_results1.deleteRow(ds_results1.getRowPosition());
        }
    }

    scwin.f_switchObjMode(7); //행삭제, 취소
}

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_CancelRow = function (gubun) {
    if (gubun == null || gubun == "" || gubun == 0) {
        $c.data.undoRow(ds_results1, false);
    }

    scwin.f_switchObjMode(7); //행삭제, 취소
}

//-------------------------------------------------------------------------
// 조회조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    if (scwin.gv_userClsCd != "01") {
        $c.gus.cfInitObjects(tbl_srchCond, [acb_con_workGubun, ed_dptIntendDd, ed_clntNo, ed_clntNm]);
    } else {
        $c.gus.cfInitObjects(tbl_srchCond, [acb_con_workGubun, ed_dptIntendDd]);
    }
}

//-------------------------------------------------------------------------
// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_orderDetail = function () {
    var row = ds_results.getRowPosition();
    var strOrderDetailUrl = "";
    var programId = "";

    if (row > 0) {
        // 선택된 오더 정보 : 오더번호 / 오더유형
        var v_odrNo = ds_results.getCellData(row, "odrNo");

        var paramObj = {
            odrNo: v_odrNo,
            type: retrieve
        };

        if (v_transCargoClsCd == "scwin. DsConstants.ODR_BULK") {
            // 오더 종류가 벌크오더인 경우 - 화물구분(B : 벌크)
            strOrderDetailUrl = DsConstants.URL_BULK_ORDER;
            programId = "sd_402_01_02t.jsp";

            $c.win.openMenu("벌크오더", strOrderDetailUrl, programId, paramObj);
        } else {
            // 오더 종류가 컨테이너 오더인 경우 - 화물구분 (C : 컨테이너)
            strOrderDetailUrl = DsConstants.URL_CONTAINER_ORDER;
            programId = "sd_402_01_11t.jsp";

            $c.win.openMenu("컨테이너오더", strOrderDetailUrl, programId, paramObj);
        }

    } else {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, new Array("오더현황"));
        return;
    }
}

