//-------------------------------------------------------------------------
// 오더완료여부체크
//-------------------------------------------------------------------------   
scwin.f_isCompleteOrder = function (p_dataset, p_row) {
    if (p_dataset.getRowCount() == 0) {
        return false;
    }

    if (p_dataset.getCellData(p_row, "odrCompleteYn") == 1) {
        return true;
    }

    return false;
};

//-------------------------------------------------------------------------
