//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    tbx_totalRows.setValue(ds_results.getRowCount());

    if (ds_results.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    } else {
        ds_results.setRowPosition(0);
    }

    scwin.f_switchObjMode(5); //조회완료

    scwin.f_Retrieve(1);
};

//-------------------------------------------------------------------------
// 조회1 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve1_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    scwin.ds_results1_OnLoadCompleted();
    scwin.ds_results2_OnLoadCompleted()
};

//-------------------------------------------------------------------------
// ds_results1 로드완료후 처리
//-------------------------------------------------------------------------
scwin.ds_results1_OnLoadCompleted = function () {
    tbx_totalRows1.setValue(ds_results1.getRowCount());

    if (ds_results1.getRowCount() == 0) {
        return;
    }

    ds_results1.setRowPosition(0); //tobe 추가

    if (scwin.f_isCompleteOrder(ds_results, ds_results.getRowPosition())) {
        gr_results1.setReadOnly("grid", true);

    } else {
        gr_results1.setReadOnly("grid", false);
    }
};

//-------------------------------------------------------------------------
// ds_results1 로드완료후 처리
//-------------------------------------------------------------------------
scwin.ds_results2_OnLoadCompleted = function () {
    ds_results2.setRowPosition(0); //tobe 추가
    tbx_totalRows2.setValue(ds_results2.getRowCount());
};

//-------------------------------------------------------------------------
// 저장 submitdone
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다.

    scwin.f_Retrieve();
