//-------------------------------------------------------------------------
// 운송물량 그리드 : 완료여부 displayFormatter
//-------------------------------------------------------------------------
scwin.odrCompleteYnExp = function (data) {
    return $c.gus.decode(data, 1, "Y", "N");
};

//-------------------------------------------------------------------------
// 운송물량 그리드 : 출발예정일시 컬럼 customFormatter
//-------------------------------------------------------------------------
scwin.wrkStDtExp = function (data, formatData, rowIdx, colIdx) {
    let wrkStHh = ds_results.getCellData(rowIdx, "wrkStHh");
    let wrkStDt = "";

    if (!$c.util.isEmpty(data)) {
        wrkStDt = data.substring(2, 4) + "-" + data.substring(4, 6) + "-" + data.substring(6, 8);

        if (!$c.util.isEmpty(wrkStHh)) {
            wrkStDt += " " + wrkStHh.substring(0, 2) + ":" + wrkStHh.substring(2, 4);
        }
    }

    return wrkStDt;
};

//-------------------------------------------------------------------------
// 운송물량 그리드 : 도착예정일시 컬럼 customFormatter
//-------------------------------------------------------------------------
scwin.wrkEndDtExp = function (data, formatData, rowIdx, colIdx) {
    let wrkEndHh = ds_results.getCellData(rowIdx, "wrkEndHh");
    let wrkEndDt = "";

    if (!$c.util.isEmpty(data)) {
        wrkEndDt = data.substring(2, 4) + "-" + data.substring(4, 6) + "-" + data.substring(6, 8);

        if (!$c.util.isEmpty(wrkEndHh)) {
            wrkEndDt += " " + wrkEndHh.substring(0, 2) + ":" + wrkEndHh.substring(2, 4);
        }
    }

    return wrkEndDt;
};

