// 운송차량 그리드 : 회원 컬럼 displayFormatter
//-------------------------------------------------------------------------
scwin.mbssysVehclYnExp = function (data) {
    return $c.gus.decode(data, 1, "Yes", "No");
};

//-------------------------------------------------------------------------
// 운송물량 dataList onrowpositionchange
// ASIS : ds_results OnRowPosChanged(row)
//-------------------------------------------------------------------------
scwin.ds_results_onrowpositionchange = function (info) {
    if (ds_results.getRowCount() == 0 || scwin.pos_groupCode == ds_results.getRowPosition())
        return;

    if (ds_results.getCellData(ds_results.getRowPosition(), "coshippingNo") != "") {
        gr_results.setCellReadOnly(info.newRowIndex, "indvdlAlloccarYn", true);
    } else {
        gr_results.setCellReadOnly(info.newRowIndex, "indvdlAlloccarYn", false);
    }

    scwin.pos_groupCode = ds_results.getRowPosition();
    scwin.f_Retrieve(1);

};

//-------------------------------------------------------------------------
// 운송차량 dataList onrowpositionchange
// ASIS : ds_results1 OnRowPosChanged(row)
//-------------------------------------------------------------------------
scwin.ds_results1_onrowpositionchange = function (info) {
    if (ds_results1.getRowCount() == 0 || ds_results1.getRowPosition() == 0)
        return;

    if (ds_results1.getRowStatus(info.newRowIndex) == "C") {
        gr_results1.setCellReadOnly(info.newRowIndex, "vehclShortCd", false);
    } else {
        gr_results1.setCellReadOnly(info.newRowIndex, "vehclShortCd", true);
    }
};

//-------------------------------------------------------------------------
// 운송차량 그리드 : 단축번호 컬럼 검색
// ASIS : gr_results1 OnPopup(row,colid,data)
//-------------------------------------------------------------------------
scwin.gr_results1_ontextimageclick = function (rowIndex, columnIndex) {
    switch (columnIndex) {
        case 1: //vehclShortCd
            if (ds_results1.getCellData(ds_results1.getRowPosition(), 'spotYn') == 1) {
                scwin.f_vehclSearch(false, false, true);
            } else {
                scwin.f_vehclSearch(false, false, false);
            }
            break;
    }

};

//-------------------------------------------------------------------------
// 운송차량 dataList : 단축번호 컬럼 값 변경
// ASIS : gr_results1 OnExit(row,colid,olddata)
//-------------------------------------------------------------------------
scwin.ds_results1_oncelldatachange = function (info) {
    switch (info.colID) {
        // case "vehclShortCd":
        //     if (ds_results1.getCellData(info.rowIndex, info.colID) != "" && ds_results1.getCellData(info.rowIndex, info.colID) != info.oldValue) {
        //         if (ds_results1.getCellData(ds_results1.getRowPosition(), 'spotYn') == 1) {
        //             scwin.f_vehclSearch(false, true, true);
        //         } else {
        //             scwin.f_vehclSearch(false, true, false);
        //         }
        //     }
        //     break;

        case "eqKndNm":
            //차량종류콤보에서 해당코드값이 있을때 규격을 지운다
            if (ds_results1.getCellData(info.rowIndex, "eqKndNm") != "") {
                var tmpRsData = ds_eqKndCd.getMatchedIndex("code", ds_results1.getCellData(info.rowIndex, "eqKndNm"));

                if (tmpRsData.length != 0) {
                    ds_results1.setCellData(info.rowIndex, "eqKndCd", ds_results1.getCellData(row, "eqKndNm"));
                    ds_results1.setCellData(info.rowIndex, "eqNrmCd", "");
                    ds_results1.setCellData(info.rowIndex, "eqNrmNm", "");
                }
            }
            break;

        case "eqNrmNm":
            if (ds_results1.getCellData(info.rowIndex, "eqNrmNm") != "") {
                var tmpRsData = ds_eqNrmCd.getMatchedIndex("code", ds_results1.getCellData(info.rowIndex, "eqNrmNm"));

                if (tmpRsData.length != 0) {
                    ds_results1.setCellData(info.rowIndex, "eqNrmCd", ds_results1.getCellData(info.rowIndex, "eqNrmNm"));
                    ds_results1.setCellData(info.rowIndex, "eqNrmNm", ds_eqNrmCd.getCellData(tmpRsData[0], "name"));
                }
            }
            break;
    }
};

//-------------------------------------------------------------------------
// 운송차량 그리드 oncolumnindexchange
// ASIS : gr_results1 OnColumnPosChanged(row,colid)
//-------------------------------------------------------------------------
scwin.gr_results1_oncolumnindexchange = function (columnIndex, oldColumnIndex) {
    var v_eqKndCd = ds_results1.getCellData(ds_results1.getRowPosition(), "eqKndCd");

    if (columnIndex == 4 && v_eqKndCd != "") { //4:eqNrmNm
        //계약거래처가 동부한농화학이고 품목이 복합비료인경우에는 차량규격중 5, 25Ton만 가능하다
        scwin.f_vehclNrm(v_eqKndCd);
    }
};

