//-------------------------------------------------------------------------
// SPOT차량 버튼 클릭(박인선pl 삭제요청)
//-------------------------------------------------------------------------
// scwin.btn_spot_onclick = function (e) {
//     scwin.f_vehclSearch(true, false, true);
// };

scwin.ed_workIndictNo_oneditkeyup = function (info, e) {
    var val = this.getValue().toUpperCase();
    this.setValue(val); // 실시간 대문자 반영

    if (val.length > 0) {
        // 1. 첫 글자가 영문이 아닌 경우 즉시 삭제
        if (val.length === 1 && !/[A-Z]/.test(val)) {
            this.setValue("");
        }
        // 2. 두 번째 글자부터 숫자가 아닌 것이 들어오면 마지막 글자 삭제
        if (val.length > 1) {
            var subVal = val.substring(1);
            if (/[^0-9]/.test(subVal)) {
                this.setValue(val.substring(0, 1) + subVal.replace(/[^0-9]/g, ""));
            }
        }
    }

};
